import{j as i,D as l,b as t,c as r,a2 as a,g as c,h as o,f as p,G as n,a3 as s}from"./chunks/framework.BDRKwY9B.js";const B=JSON.parse('{"title":"平台运行时","description":"理解 ApplicationHost、PlatformAPI 与 App 之间的运行时关系，以及 Platform 与 Kernel、Brain 的边界。","frontmatter":{"title":"平台运行时","description":"理解 ApplicationHost、PlatformAPI 与 App 之间的运行时关系，以及 Platform 与 Kernel、Brain 的边界。","order":2},"headers":[],"relativePath":"architecture/platform-runtime.md","filePath":"architecture/platform-runtime.md","lastUpdated":1778839555000}'),A={name:"architecture/platform-runtime.md"};function m(h,e,u,_,f,E){const d=l("Mermaid");return t(),r("div",null,[e[1]||(e[1]=a('<h1 id="平台运行时" tabindex="-1">平台运行时 <a class="header-anchor" href="#平台运行时" aria-label="Permalink to &quot;平台运行时&quot;">​</a></h1><p><strong>挼挼如是说</strong></p><blockquote><p>打个比方：platform 是插座，app 是电器。插座不关心你插的是电饭煲还是手机充电器，它只负责通电。app 也不关心电是怎么发的，它只负责干自己的活。</p></blockquote><h2 id="体系总述" tabindex="-1">体系总述 <a class="header-anchor" href="#体系总述" aria-label="Permalink to &quot;体系总述&quot;">​</a></h2><p><code>platform</code>：</p><ul><li>找到启用的应用，把它们运行起来</li><li>读 <code>manifest.yaml</code>，搞清楚每个 app 能干什么</li><li>给每个 app 塞一根 <code>PlatformAPI</code> 的管子</li><li>把命令记在表上、把事件排进队列</li><li>管理 app 从启动到停止的完整生命周期</li></ul><p><code>Apps</code>：</p><ul><li>从外面接收输入</li><li>把输入变成标准化事件扔出去</li><li>暴露干脆利落的命令</li><li>管好自己的小仓库</li></ul><div class="tip custom-block"><p class="custom-block-title">💡 小贴士</p><p>所以说，App 就像是 <strong>传感器 + 执行器</strong></p></div><h2 id="启动链路" tabindex="-1">启动链路 <a class="header-anchor" href="#启动链路" aria-label="Permalink to &quot;启动链路&quot;">​</a></h2>',10)),(t(),c(s,null,{default:o(()=>[n(d,{id:"mermaid-77",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20ROW1%5B%22%E6%B3%A8%E5%86%8C%E9%98%B6%E6%AE%B5%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20START%5B%22NoneBot%20Startup%22%5D%0A%20%20%20%20%20%20%20%20LOADCFG%5B%22Load%20apps%2Fconfig.yaml%22%5D%0A%20%20%20%20%20%20%20%20REGISTER%5B%22Register%20Apps%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ROW2%5B%22%E8%BF%90%E8%A1%8C%E9%98%B6%E6%AE%B5%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20BIND%5B%22Bind%20PlatformAPI%22%5D%0A%20%20%20%20%20%20%20%20APPSTART%5B%22app.on_start()%22%5D%0A%20%20%20%20%20%20%20%20LOOP%5B%22run_app_loop()%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ROW3%5B%22%E4%BA%8B%E4%BB%B6%E8%BE%93%E5%87%BA%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20TICK%5B%22host.tick()%22%5D%0A%20%20%20%20%20%20%20%20APPTICK%5B%22app.on_tick()%22%5D%0A%20%20%20%20%20%20%20%20EMIT%5B%22emit%20AppEvent%22%5D%0A%20%20%20%20%20%20%20%20QUEUE%5B%22Event%20Queue%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20START%20--%3E%20LOADCFG%0A%20%20%20%20LOADCFG%20--%3E%20REGISTER%0A%20%20%20%20REGISTER%20--%3E%20BIND%0A%20%20%20%20BIND%20--%3E%20APPSTART%20--%3E%20LOOP%0A%20%20%20%20LOOP%20--%3E%20TICK%0A%20%20%20%20TICK%20--%3E%20APPTICK%20--%3E%20EMIT%20--%3E%20QUEUE%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[p(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="核心对象" tabindex="-1">核心对象 <a class="header-anchor" href="#核心对象" aria-label="Permalink to &quot;核心对象&quot;">​</a></h2><h3 id="applicationhost-—-宿主管家" tabindex="-1"><code>ApplicationHost</code> — 宿主管家 <a class="header-anchor" href="#applicationhost-—-宿主管家" aria-label="Permalink to &quot;`ApplicationHost` — 宿主管家&quot;">​</a></h3><p><code>ApplicationHost</code> 是 app 们的房东，目前身兼数职：</p><ul><li>管着所有 app 实例</li><li>管着命令注册表</li><li>管着事件队列</li></ul><p>已经提供的接口：</p><ul><li><code>register()</code> — 注册 app 实例</li><li><code>tick()</code> — 驱动所有 app 执行一个周期</li><li><code>stop_all()</code> — 停止全部应用</li><li><code>drain_events()</code> — 取出积压事件</li><li><code>invoke_command()</code> — 调用指定 app 的命令</li></ul><h3 id="platformapi-—-管子" tabindex="-1"><code>PlatformAPI</code> — 管子 <a class="header-anchor" href="#platformapi-—-管子" aria-label="Permalink to &quot;`PlatformAPI` — 管子&quot;">​</a></h3><p>这是平台塞给每个 app 的万能插座。app 通过它跟外界打交道：</p><ul><li><code>emit_event()</code> — 喊一嗓子：&quot;出事了！&quot;</li><li><code>register_command()</code> — &quot;我会干这个&quot;</li><li><code>data_dir</code> — 我的小仓库</li><li><code>package</code> — 我是谁</li><li><code>log()</code> — 记个日志</li></ul><h2 id="内建应用概览" tabindex="-1">内建应用概览 <a class="header-anchor" href="#内建应用概览" aria-label="Permalink to &quot;内建应用概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>App</th><th>靠什么知道外面的事</th><th>能干什么</th><th>会喊什么</th><th>自己存什么</th></tr></thead><tbody><tr><td><code>qq</code></td><td>NoneBot <code>on_message</code></td><td>发群消息、发私聊、群内 @ 人</td><td><code>message.received</code></td><td><code>qq_events.json</code> 之类</td></tr><tr><td><code>alarm</code></td><td>时间轮询、<code>on_tick()</code></td><td><code>set_alarm</code> 设闹钟</td><td><code>alarm_reminder</code>、<code>diary_prompt</code></td><td><code>alarms.json</code>、<code>config.json</code></td></tr><tr><td><code>diary</code></td><td>被命令叫醒</td><td><code>write_diary</code> 写日记</td><td><code>diary.written</code></td><td><code>diaries.json</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">🪧 告示牌</p><p>内建应用还在持续迭代中，后续版本将逐步完善功能。</p></div><h2 id="下一步阅读" tabindex="-1">下一步阅读 <a class="header-anchor" href="#下一步阅读" aria-label="Permalink to &quot;下一步阅读&quot;">​</a></h2><ul><li>想写自己的应用：读 <a href="./../develop/app-development.html">App 开发指南</a></li></ul>',14))])}const b=i(A,[["render",m]]);export{B as __pageData,b as default};
